const payload = $input.first().json.body;
if (payload?.event !== 'messages.upsert') {
  return [{ json: { skip: true, motivo: `Evento ignorado: ${payload?.event}` } }];
}
const data = payload?.data;
const key = data?.key;
if (key?.fromMe === true) {
  return [{ json: { skip: true, motivo: 'Mensaje propio (fromMe)' } }];
}
const remoteJid = key?.remoteJid || '';
if (remoteJid.endsWith('@g.us')) {
  return [{ json: { skip: true, motivo: 'Mensaje de grupo' } }];
}
const telefono = remoteJid.split('@')[0];
const messageType = data?.messageType;
const message = data?.message;
let texto = null;
if (messageType === 'conversation') {
  texto = message?.conversation ?? null;
} else if (messageType === 'extendedTextMessage') {
  texto = message?.extendedTextMessage?.text ?? null;
}
return [{
  json: {
    telefono,
    remoteJid,
    tipo: messageType,
    texto,
    contacto: data?.pushName || telefono,
    messageId: key?.id,
    instanceName: payload?.instance,
    skip: !texto
  }
}];

